 // String applicationName = "TNNAS - PharmacyKeeper - Saint Thomas Dekalb Hospital";
 //String applicationName =  "TNNAS - PowerInsight";
  //String app="TNNAS - PowerInsight";
  /// String applicationName =  "INEVA/ININD - Synapse IQ Reporting";
  //String app="SynapseIQReporting";
  int count = 0;

  String fileName = "D:/" + app + "-AttrAssignments123.csv";
  BufferedWriter outFile = new BufferedWriter(new FileWriter(fileName));

  //Write header
  outFile.write("Username,FirstName,LastName,EmployeeId,Email,Department,Attribute,Role,App");
  outFile.newLine();
  outFile.flush();

  QueryOptions qo = new QueryOptions();  
  qo.addFilter(Filter.ne("name","spadmin"));
  qo.setCloneResults(true);
  Iterator it = context.search(Identity.class, qo, "name");

  while(it.hasNext()){
    count++;
    String identityName = it.next()[0];

    try{
      Identity identity = context.getObjectByName(Identity.class, identityName);

      if(identity == null)
        continue;

      if(null!=identity){
        List assignments = identity.getAttributeAssignments();
        if(assignments != null && !assignments.isEmpty()){
          for (Object assignmentObj : assignments){
            AttributeAssignment assignment = (AttributeAssignment)assignmentObj;
          //  if(assignment.getApplicationName().equalsIgnoreCase(applicationName)){
             if(assignment.getApplicationName().startsWith(applicationName)){ 
              
              outFile.write(assignment.getNativeIdentity() + ","+identity.getAttribute("firstname")+","+ identity.getAttribute("lastname")+","+identity.getAttribute("samAccountName")+","+identity.getEmail()+","+identity.getAttribute("department")+
                            ","+assignment.getName()+","+ assignment.getStringValue()+","+assignment.getApplicationName());
              outFile.newLine();
              outFile.flush();
            }
          }
        }

        List roleAssignments = identity.getRoleAssignments();

        if(roleAssignments != null && !roleAssignments.isEmpty()){
          for (Object assignmentRoleObj : roleAssignments){
            RoleAssignment roleassignment = (RoleAssignment)assignmentRoleObj;

            List roleTargets=roleassignment.getTargets();
            if(roleTargets != null && !roleTargets.isEmpty()){
              for (RoleTarget roleTrgt : roleTargets){
                if(roleTrgt.getApplicationName().equalsIgnoreCase(applicationName)){
                  String roleName = roleassignment.getRoleName();
                  Bundle roleObj = context.getObjectByName(Bundle.class,roleName);
                  if(null!=roleObj){
                    if(roleObj.getType().equalsIgnoreCase("Business")){
                      List requiredRoles = roleObj.getRequirements();
                      if(null!=requiredRoles){
                        for (Object requiredRole : requiredRoles) {
                          //return requiredRole;
                          List profiles = ((Bundle) requiredRole).getProfiles();
                          if(null!=profiles){
                            for(int i=0; i < profiles.size(); i++){
                              Object profile = profiles.get(i);
                              if(null!=profile){
                                List profIter = ((Profile) profile).getConstraints();
                                if(null!=profIter){
                                  for(int j=0; j < profIter.size(); j++) {
                                    Object filter = profIter.get(j);
                                    if(null!=filter && filter instanceof sailpoint.object.Filter.LeafFilter){
                                      //return filter;
                                      Object value = ((sailpoint.object.Filter.LeafFilter) filter).getValue();
                                      String property = ((sailpoint.object.Filter.LeafFilter) filter).getProperty();
                                      if(null!=value && Util.isNotNullOrEmpty(property) ){
                                        try{
                                          String profileAppName = ((Profile) profile).getApplication().getName();
                                         // if(Util.isNotNullOrEmpty(profileAppName) && profileAppName.equalsIgnoreCase(applicationName)){
                                          if(Util.isNotNullOrEmpty(profileAppName) && profileAppName.startsWith(applicationName)){
                                            String maValue = "";
                                            if(value instanceof List){
                                              maValue = ((List) value).get(0).toString();
                                            } else{
                                              maValue = value.toString();
                                            }
                                            /* HashMap fileWriteArgs = new HashMap();
                                            fileWriteArgs.put("Username",roleTrgt.getNativeIdentity());
                                            fileWriteArgs.put("Attribute",property);
                                            fileWriteArgs.put("Role",maValue);
                                            writeToFile(applicationName,fileWriteArgs,identity);*/
                                            username = roleTrgt.getNativeIdentity();
                                            outFile.write(username+ ","+identity.getAttribute("firstname")+","+ identity.getAttribute("lastname")+","+identity.getName()+","+identity.getAttribute("samAccountName")+","+identity.getAttribute("department")
                                                          +","+property+","+maValue+","+profileAppName);
                                            outFile.newLine();
                                            outFile.flush();

                                          }
                                        } catch(Exception e){
                                          //TODO

                                        }
                                      }
                                    }
                                  }
                                }
                              }
                            }
                          }
                        }
                      }
                    }else if(roleObj.getType().equalsIgnoreCase("IT") || roleObj.getType().equalsIgnoreCase("ASCIT")){
                      List profiles = roleObj.getProfiles();
                      if(null!=profiles){
                        for(int i=0; i < profiles.size(); i++){
                          Object profile = profiles.get(i);
                          if(null!=profile){
                            List profIter = ((Profile) profile).getConstraints();
                            if(null!=profIter){
                              for(int j=0; j < profIter.size(); j++) {
                                Object filter = profIter.get(j);
                                if(null!=filter && filter instanceof sailpoint.object.Filter.LeafFilter){
                                  //return filter;
                                  Object value = ((sailpoint.object.Filter.LeafFilter) filter).getValue();
                                  String property = ((sailpoint.object.Filter.LeafFilter) filter).getProperty();
                                  if(null!=value && Util.isNotNullOrEmpty(property)){
                                    try{
                                      String profileAppName = ((Profile) profile).getApplication().getName();
                                     // if(Util.isNotNullOrEmpty(profileAppName) && profileAppName.equalsIgnoreCase(applicationName)){
                                        if(Util.isNotNullOrEmpty(profileAppName) && profileAppName.startsWith(applicationName)){
                                        String maValue = "";
                                        if(value instanceof List){
                                          maValue = ((List) value).get(0).toString();
                                        } else{
                                          maValue = value.toString();
                                        }
                                        /*HashMap fileWriteArgs = new HashMap();
                                        fileWriteArgs.put("Username",roleTrgt.getNativeIdentity());
                                        fileWriteArgs.put("Attribute",property);
                                        fileWriteArgs.put("Role",maValue);
                                        writeToFile(applicationName,fileWriteArgs,identity);
                                        username = roleTrgt.getNativeIdentity();*/
                                        username = roleTrgt.getNativeIdentity();
                                         outFile.write(username+ ","+identity.getAttribute("firstname")+","+ identity.getAttribute("lastname")+","+identity.getAttribute("samAccountName")+","+identity.getEmail()+","+identity.getAttribute("department")+
                                                       ","+property+","+maValue+","+profileAppName);
                                             outFile.newLine();
                                        outFile.flush();


                                      }
                                    } catch(Exception e){
                                      //TODO
                                    }
                                  }
                                }
                              }
                            }
                          }
                        }
                      }

                    }
                  }

                }
              }
            }
          }
        }
      }

      if ((count % 1000) == 0) {
        context.decache();
       // System.out.println("Count: " +count); 
      }
    } catch (Exception e) {  
      //Log any errors encountered during saving the object  
    }
  }

  if(null!=outFile){
    outFile.close();
  }

  return count;
